// Extract charging data from payload
const vehicle = msg.payload.vehicles && msg.payload.vehicles[0] ? msg.payload.vehicles[0] : {};

// Helper to recursively find a value in nested object
function findValue(obj, key) {
    if (!obj || typeof obj !== 'object') return null;
    if (key in obj) return obj[key];
    for (const k in obj) {
        const found = findValue(obj[k], key);
        if (found !== null) return found;
    }
    return null;
}

// Helper to get value by dot-notation path
function getValueByPath(obj, path) {
    if (!obj || typeof obj !== 'object') return null;
    const keys = path.split('.');
    let current = obj;
    for (const key of keys) {
        if (current == null || typeof current !== 'object') return null;
        current = current[key];
    }
    return current;
}

// Find all values recursively in the vehicle object
const soc = findValue(vehicle, 'stateOfChargeInPercent') || 0;
const power = findValue(vehicle, 'chargePowerInKw') || 0;
const chargedAt = findValue(vehicle, 'fullyChargedAt') || null;
const range = findValue(vehicle, 'totalRangeInKm') || 0;
const targetSoc = findValue(vehicle, 'targetStateOfChargeInPercent') || 0;
const remainingTime = findValue(vehicle, 'remainingTimeToFullyChargedInMinutes') || 0;
const capacity = findValue(vehicle, 'capacityInKWh') || 0;
const doorsLocked = findValue(vehicle, 'doorsLocked') || false;
const locked = findValue(vehicle, 'locked') || false;
const windows = findValue(vehicle, 'windows') || null;
const sunroof = findValue(vehicle, 'sunroof') || null;
const trunk = findValue(vehicle, 'trunk') || null;
const mileage = findValue(vehicle, 'mileageInKm') || 0;
const batteryState = getValueByPath(vehicle, 'charging.status.state') || null;

const data = {
    stateOfChargeInPercent: soc,
    chargePowerInKw: power,
    fullyChargedAt: chargedAt,
    totalRangeInKm: range,
    targetStateOfChargeInPercent: targetSoc,
    remainingTimeToFullyChargedInMinutes: remainingTime,
    capacityInKWh: capacity,
    doorsLocked: doorsLocked,
    locked: locked,
    windows: windows,
    sunroof: sunroof,
    trunk: trunk,
    mileageInKm: mileage,
    batteryState: batteryState
};

// Create separate messages for each MQTT topic
const messages = [];

for (const [key, value] of Object.entries(data)) {
    messages.push({
        topic: `stat/myskoda/${key}`,
        payload: value,
        qos: 0,
        retain: true
    });
}

// Add the charge power for delay calculation
messages.push({
    payload: power,
    topic: ""
});

return messages;

// Set delay based on charging status
const power = msg.payload || 0;
// 30 seconds if charging, 5 minutes if not
const delayMs = power > 0 ? 30000 : 300000;
msg.delay = delayMs;
return msg;
